   ```typescript
   const currency = (invoice.currency ?? "usd").toUpperCase();
   if (currency !== "USD") {
     log.error("Stripe renewal: non-USD currency rejected", {
       invoiceId, subscriptionId, currency, telegramUserId, resolvedPlanId,
     });
     return;
   }
   const amountCents = invoice.amount_paid ?? 0;
   ```

